/** Computes the next generation of live cells per Conway's Game of Life rules. */
export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveCellKeys = new Set(liveCells.map(([x, y]) => key(x, y)));
  const countNeighbors = (x: number, y: number) => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCellKeys.has(key(x + dx, y + dy))) count++;
      }
    }
    return count;
  };
  const survives = ([x, y]: LiveCell) => {
    const neighborCount = countNeighbors(x, y);
    return neighborCount === 2 || neighborCount === 3;
  };
  const deadNeighborKeys = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        if (!liveCellKeys.has(k)) deadNeighborKeys.add(k);
      }
    }
  }
  const births: LiveCell[] = [];
  for (const k of deadNeighborKeys) {
    const [xs, ys] = k.split(",");
    const x = Number(xs);
    const y = Number(ys);
    if (countNeighbors(x, y) === 3) births.push([x, y]);
  }
  return [...liveCells.filter(survives), ...births];
}

